  ) |&gt;
  mutate(
    day = as.integer(str_remove(day, "mood_day"))  # clean up the day variable
  )

31.3 Detecting Autocorrelation in Your Residuals
The first diagnostic step: after fitting a model without an AR structure, check whether the residuals show serial dependence.


Code
n_people &lt;- 40
n_days   &lt;- 20

# Simulate multilevel AR(1) data
df_ar &lt;- expand_grid(person = 1:n_people, day = 1:n_days) |&gt;
  arrange(person, day) |&gt;
  group_by(person) |&gt;
  mutate(
    baseline  = rnorm(1, 50, 6),
    ar_resid  = {
      r &lt;- numeric(n_days); r[1] &lt;- rnorm(1, 0, 3)
      for (t in 2:n_days) r[t] &lt;- 0.7 * r[t-1] + rnorm(1, 0, 3)
      r
    },
    Y = baseline + 2 * day / n_days + ar_resid
  ) |&gt;
  ungroup() |&gt;
  mutate(person = factor(person))

# Fit naive model (ignores AR structure)
m_naive &lt;- lme(Y ~ day, random = ~1 | person, data = df_ar)

# Check residual ACF
residuals_df &lt;- data.frame(
  resid  = residuals(m_naive, type = "normalized"),
  person = df_ar$person,
  day    = df_ar$day
)

# Lag-1 autocorrelation per person
lag1_by_person &lt;- residuals_df |&gt;
  group_by(person) |&gt;
  arrange(day) |&gt;
  summarise(lag1 = cor(head(resid, -1), tail(resid, -1)))

ggplot(lag1_by_person, aes(x = lag1)) +
  geom_histogram(fill = "#1e3a5f", color = "white", bins = 15) +
  geom_vline(xintercept = 0, linetype = "dashed", color = "#e63946") +
  labs(
    title    = "Lag-1 autocorrelation of residuals (naive model)",
    subtitle = "Most values are positive — indicates AR structure in the residuals",
    x        = "Lag-1 autocorrelation",
    y        = "Count"
  ) +
  theme_minimal(base_size = 13)









Most lag-1 autocorrelations are positive — strong evidence of serial dependence that the naive model is ignoring.

35.4 Step 2: Complete-Case vs. Available-Case Analysis
Complete-case analysis uses only observations with no missing values at any wave. It is simple but biased when dropouts differ from completers.
Available-case analysis uses all available data at each wave (mixed model with lmer uses this by default). It is more efficient than complete-case and is unbiased under MAR when the model is correctly specified — because the random effects model uses all available information to recover the full trajectory.


Code
# Approach 1: Complete cases only
df_complete_only &lt;- df_obs |&gt;
  group_by(person) |&gt;
  filter(sum(!is.na(Y_obs)) == n_waves) |&gt;
  ungroup()

m_cc &lt;- lmer(Y_obs ~ wave * treatment + (1 | person), data = df_complete_only)

# Approach 2: Available case (lmer handles missingness automatically)
m_ac &lt;- lmer(Y_obs ~ wave * treatment + (1 | person), data = df_obs)

bind_rows(
  broom.mixed::tidy(m_cc, effects = "fixed") |&gt;
    filter(term == "wave:treatment1") |&gt;
    mutate(approach = "Complete-case"),
  broom.mixed::tidy(m_ac, effects = "fixed") |&gt;
    filter(term == "wave:treatment") |&gt;
    mutate(approach = "Available-case (lmer)")
) |&gt;
  select(approach, estimate, std.error, p.value) |&gt;
  knitr::kable(
    digits = 3,
    caption = "Treatment × wave interaction: complete-case vs. available-case. True effect ≈ 5."
  )



